export interface ToolbarProps {
  container?: HTMLElement | ToolbarConfig | null;
  handlers?: Record<string, Handler>;
  option?: number;
  module?: boolean;
  theme?: boolean;
}

class Toolbar extends Module<ToolbarProps> {
  static DEFAULTS: ToolbarProps;

  private static sharedContainers = new WeakMap<HTMLElement, SharedToolbar>();

  container?: HTMLElement | null;
  controls: [string, HTMLElement][];
  handlers: Record<string, Handler>;
  private shared?: SharedToolbar;
  private editorChangeHandler: (...args: any[]) => void;
  private focusHandler: () => void;

  constructor(quill: Quill, options: Partial<ToolbarProps>) {
    super(quill, options);
    if (Array.isArray(this.options.container)) {
      const container = document.createElement('div');
      container.setAttribute('role', 'toolbar');
      addControls(container, this.options.container);
      quill.container?.parentNode?.insertBefore(container, quill.container);
      this.container = container;
    } else if (typeof this.options.container === 'string') {
      this.container = document.querySelector(this.options.container);
    } else {
      this.container = this.options.container;
    }
    if (!(this.container instanceof HTMLElement)) {
      debug.error('Container required for toolbar', this.options);
      return;
    }
    this.controls = [];
    this.handlers = {};
    if (this.options.handlers) {
      Object.keys(this.options.handlers).forEach((format) => {
        const handler = this.options.handlers?.[format];
        if (handler) {
          this.addHandler(format, handler);
        }
      });
    }
    this.shared = Toolbar.sharedContainers.get(this.container);
    if (this.shared == null) {
      this.shared = new SharedToolbar(this.container);
      Toolbar.sharedContainers.set(this.container, this.shared);
    }
    this.shared.add(this);
    this.editorChangeHandler = (type: string, range: Range | null) => {
      if (type === Quill.events.SELECTION_CHANGE && range != null) {
        this.shared?.activate(this);
      }
    };
    this.focusHandler = () => this.shared?.activate(this);
    this.quill.on(Quill.events.EDITOR_CHANGE, this.editorChangeHandler);
    this.quill.root.addEventListener('focusin', this.focusHandler);
  }

  addHandler(format: string, handler: Handler) {
    this.handlers[format] = handler;
  }

  attach(input: HTMLElement) {
    this.shared?.attach(input);
  }

  getActive() {
    return this.shared?.active;
  }

  setPickerUpdater(update: () => void) {
    this.shared?.setPickerUpdater(update);
  }

  private dispose() {
    this.quill.off(Quill.events.EDITOR_CHANGE, this.editorChangeHandler);
    this.quill.root.removeEventListener('focusin', this.focusHandler);
  }

  update(range: Range | null) {
    this.shared?.update(range);
  }
}

class SharedToolbar {
  toolbars = new Set<Toolbar>();
  controls: [string, HTMLElement][] = [];
  active?: Toolbar;
  private attached = new WeakSet<HTMLElement>();
  private observer: MutationObserver;
  private pickerUpdater?: () => void;

  constructor(private container: HTMLElement) {
    this.container.classList.add('ql-toolbar');
    this.attachAll();
    this.observer = new MutationObserver(() => {
      this.prune();
      this.attachAll();
    });
    this.observer.observe(this.container.ownerDocument.documentElement, {
      childList: true,
      subtree: true,
    });
  }

  add(toolbar: Toolbar) {
    this.toolbars.add(toolbar);
    this.attachAll();
  }

  setPickerUpdater(update: () => void) {
    if (this.pickerUpdater == null) this.pickerUpdater = update;
  }

  activate(toolbar: Toolbar) {
    this.prune();
    if (!this.toolbars.has(toolbar)) return;
    this.active = toolbar;
    const [range] = toolbar.quill.selection.getRange();
    this.update(range);
  }

  private prune() {
    this.toolbars.forEach((toolbar) => {
      if (toolbar.quill.root.isConnected) return;
      toolbar.dispose();
      this.toolbars.delete(toolbar);
      if (this.active === toolbar) this.active = undefined;
